#include <filesystem>
#include <iostream>

bool file_exists(const std::string& path) {
    return std::filesystem::exists(path);
}

#include <cstdio>
#include <iostream>
#include <memory>

void run_ls() {
    auto pipe = popen("ls", "r");
    char buffer[128];
    while (fgets(buffer, sizeof(buffer), pipe) != nullptr) {
        std::cout << buffer;
    }
    pclose(pipe);
}
